import { get } from "svelte/store";
/**
 * Helper function for passing reactive variables around.
 *
 * To preserve reactivity between .svelte.ts files it is necessary to pass
 * it as an object with a getter method. If the reactive variable is directly
 * referenced then it triggers additional reactivity.
 *
 * TODO: Find (or write) a Svelte docs page describing this behavior.
 */
export function reactive(fn) {
    return {
        get current() {
            return fn();
        },
    };
}
export function writableReactive(get, set) {
    return {
        get current() {
            return get();
        },
        set current(value) {
            set(value);
        },
    };
}
export function readableToReactive(readable) {
    let current = $state(readable ? get(readable) : undefined);
    $effect(() => {
        if (readable) {
            current = get(readable);
        }
        const unsubscribe = readable?.subscribe((value) => {
            current = value;
        });
        return unsubscribe;
    });
    return {
        get current() {
            return current;
        },
    };
}
export function writableToReactive(writable) {
    let current = $state(writable ? get(writable) : undefined);
    $effect(() => {
        if (writable) {
            current = get(writable);
        }
        const unsubscribe = writable.subscribe((value) => {
            current = value;
        });
        return unsubscribe;
    });
    return {
        get current() {
            return current;
        },
        set current(value) {
            if (value !== undefined) {
                writable.set(value);
            }
        },
    };
}
